/**
 * Security-deposit handling. Correct implementation, included so the auditor's
 * precision can be measured: it must NOT raise a finding here.
 */

export interface DepositLedger {
  leaseId: string;
  amountHeld: number;
  deductions: { reason: string; amount: number }[];
}

/**
 * Under Article 20 the landlord holds the security deposit to secure
 * maintenance obligations and must return it, less lawful deductions, at the
 * end of the tenancy. This tracks deductions with a reason and returns the
 * remainder, never letting the balance go negative.
 */
export function refundableBalance(ledger: DepositLedger): number {
  const deducted = ledger.deductions.reduce((sum, d) => sum + Math.max(0, d.amount), 0);
  return Math.max(0, ledger.amountHeld - deducted);
}

export function recordDeduction(
  ledger: DepositLedger,
  reason: string,
  amount: number
): DepositLedger {
  if (amount <= 0) return ledger;
  return { ...ledger, deductions: [...ledger.deductions, { reason, amount }] };
}

/**
 * Eviction / non-renewal logic.
 */

export type EvictionReason = 'sale' | 'owner-use' | 'demolition' | 'major-works';

/**
 * Minimum months of notice, served through a notary public or by registered
 * mail, that a landlord must give to evict on one of the permitted grounds
 * after the lease expires.
 *
 * SEEDED VIOLATION (LAW26-2007/ART-25/2): Article 25(2) (as amended by Law
 * 33/2008) requires twelve (12) months' notice served via notary public or
 * registered mail. This returns 3 months.
 */
export const EVICTION_NOTICE_MONTHS = 3;

/**
 * SEEDED VIOLATION (LAW26-2007/ART-25/2): the article also requires the notice
 * to be served through a notary public or by registered mail. This code does
 * not record or enforce the service method at all.
 */
export function evictionEffectiveDate(noticeServedOn: Date): Date {
  const effective = new Date(noticeServedOn);
  effective.setMonth(effective.getMonth() + EVICTION_NOTICE_MONTHS);
  return effective;
}

export function permittedReasons(): EvictionReason[] {
  return ['sale', 'owner-use', 'demolition', 'major-works'];
}

/**
 * Notice-period logic for changing lease terms at renewal.
 */

/**
 * Minimum days of notice a party must give before the lease expiry when it
 * wants to amend any term (including rent) at renewal.
 *
 * SEEDED VIOLATION (LAW26-2007/ART-14): Article 14 (as amended by Law 33/2008)
 * requires no less than ninety (90) days. This returns 30.
 */
export const AMENDMENT_NOTICE_DAYS = 30;

export function amendmentDeadline(leaseExpiry: Date): Date {
  const deadline = new Date(leaseExpiry);
  deadline.setDate(deadline.getDate() - AMENDMENT_NOTICE_DAYS);
  return deadline;
}

export function isAmendmentNoticeTimely(noticeGivenOn: Date, leaseExpiry: Date): boolean {
  return noticeGivenOn <= amendmentDeadline(leaseExpiry);
}

/**
 * Lease registration. Under the Ejari system a tenancy contract must be
 * registered with RERA / the Dubai Land Department to be enforceable.
 */

export interface Lease {
  id: string;
  landlordId: string;
  tenantId: string;
  annualRent: number;
  ejariNumber?: string;
}

/**
 * A lease should not be treated as active/enforceable until it carries an
 * Ejari registration number.
 *
 * SEEDED VIOLATION (LAW26-2007/ART-4/2): Article 4 requires all lease
 * contracts to be registered (Ejari). This activates a lease regardless of
 * whether it has an Ejari number, so unregistered leases are treated as valid.
 */
export function activateLease(lease: Lease): Lease {
  return { ...lease, ejariNumber: lease.ejariNumber };
}

export function isEnforceable(lease: Lease): boolean {
  // Only checks the parties, not registration.
  return Boolean(lease.landlordId && lease.tenantId);
}

/**
 * Automatic renewal. Correct implementation, included to measure precision:
 * the auditor must NOT raise a finding here.
 */

import { AMENDMENT_NOTICE_DAYS } from './notice';

export interface Tenancy {
  leaseId: string;
  expiry: Date;
  termMonths: number;
}

/**
 * Under Article 6, if the tenancy expires and the tenant stays on with the
 * landlord's knowledge and no objection, the contract renews for the same term
 * (or one year, whichever is shorter) on the same conditions. This models that
 * default renewal.
 */
export function renewOnSameTerms(tenancy: Tenancy): Tenancy {
  const nextExpiry = new Date(tenancy.expiry);
  const renewalMonths = Math.min(tenancy.termMonths, 12);
  nextExpiry.setMonth(nextExpiry.getMonth() + renewalMonths);
  return { ...tenancy, expiry: nextExpiry, termMonths: renewalMonths };
}

export function daysUntilAmendmentDeadline(tenancy: Tenancy, today: Date): number {
  const deadline = new Date(tenancy.expiry);
  deadline.setDate(deadline.getDate() - AMENDMENT_NOTICE_DAYS);
  const ms = deadline.getTime() - today.getTime();
  return Math.ceil(ms / (1000 * 60 * 60 * 24));
}

/**
 * Rent-increase logic. Under Decree No. (43) of 2013 the maximum increase at
 * renewal is a slab based on how far the current rent sits below the average
 * rental value of comparable units.
 */

export interface RentReview {
  currentAnnualRent: number;
  marketAverageRent: number;
}

/**
 * Returns the maximum permitted rent increase as a fraction (0.0 - 0.20).
 *
 * SEEDED VIOLATION (DEC43-2013/ART-1): the slab thresholds and percentages
 * here do not match the decree. The decree is: 0% when rent is < 10% below
 * market; 5% when 11-20% below; 10% when 21-30% below; 15% when 31-40% below;
 * 20% when more than 40% below. This implementation uses wrong bands (starts
 * increasing too early and caps at 25%).
 */
export function maxIncreaseFraction(review: RentReview): number {
  const shortfall = (review.marketAverageRent - review.currentAnnualRent) / review.marketAverageRent;
  if (shortfall <= 0.05) return 0;
  if (shortfall <= 0.15) return 0.05;
  if (shortfall <= 0.25) return 0.1;
  if (shortfall <= 0.35) return 0.15;
  return 0.25;
}

export function proposedNewRent(review: RentReview, requestedRent: number): number {
  const cap = review.currentAnnualRent * (1 + maxIncreaseFraction(review));
  return Math.min(requestedRent, cap);
}
